var e=[{id:`L8_1`,type:`dialog`,speaker:`VILLAGER_BORDER_NULL_WOMAN`,text:{KOREA:`자, 이쪽으로 들어가. 헛간 지하로 이어질 거야.`,JPN:`さあ、ここから入って。小屋の地下に繋がってるはずよ。`,ENG:`Now, go inside here. It should be connected to the barn basement.`,TWN:`來，從這邊進去，裡面會通到穀倉的地下室。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`VILLAGER_BORDER_NULL_KIDS`,text:{KOREA:`선생님, 저희 엄마랑 아빠는 어딨어요?`,JPN:`先生、ママとパパはどこにいるの？`,ENG:`Where's Mom and Dad?`,TWN:`老師，爸爸媽媽在哪裡？`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`VILLAGER_BORDER_NULL_KIDS`,text:{KOREA:`비명소릴 들었어요. 아까 그 괴물이 엄마랑 아빠를 다치게 한 거예요?`,JPN:`悲鳴が聞こえたよ。さっきの化け物がママとパパを傷つけたの？`,ENG:`I heard a scream. Did that monster hurt my mommy and daddy?`,TWN:`我有聽到尖叫聲，是剛剛那個怪物傷害爸爸媽媽嗎？`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`VILLAGER_BORDER_NULL_WOMAN`,text:{KOREA:`부모님들은 걱정하지 않아도 돼. 지금 우리처럼 안전한 곳에 숨어 계실 거야.`,JPN:`ご両親のことは心配しなくても大丈夫よ。今の私たちのように、安全なところに隠れているはずだからね。`,ENG:`Don't worry about your parents. Right now, it's more important that you hide in a safe place.`,TWN:`大家不用擔心，你們的爸爸媽媽和我們一樣，現在都躲在安全的地方。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`VILLAGER_BORDER_NULL_WOMAN`,text:{KOREA:`그러니 내가 괜찮다고 할 때까지 절대 밖으로 나오지 마. 알겠지?`,JPN:`だから、先生が大丈夫って言うまで絶対に外に出ちゃだめよ。わかった？`,ENG:`So don't come out until I say so, okay?`,TWN:`在老師說可以出來之前，大家千萬不可以出來喔，知道嗎？`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`VILLAGER_BORDER_NULL_WOMAN`,text:{KOREA:`괜찮아… 괜찮아. 난 할 수 있어.`,JPN:`大丈夫……大丈夫。私はできる。`,ENG:`All right... I can do this... Okay...`,TWN:`沒問題…我可以的，我做得到的。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`VILLAGER_BORDER_NULL_WOMAN`,text:{KOREA:`에, 에잇!!`,JPN:`え、えいっ！！`,ENG:`H-hyah!!`,TWN:`喂，這裡！！`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`CORRUPTED_NPC_MONTSER_B`,text:{KOREA:`크르륵……?`,JPN:`グルル……？`,ENG:`Grrrr...?`,TWN:`咯嚕嚕……？`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`VILLAGER_BORDER_NULL_WOMAN`,text:{KOREA:`여기야! 이 괴물아!`,JPN:`こっちよ！　化け物！`,ENG:`Hey monster! Over here!`,TWN:`我在這裡！你這個怪物！`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`CORRUPTED_NPC_MONTSER_B`,text:{KOREA:`크워어어어!!!`,JPN:`グオオオオ！！！`,ENG:`Kroaaarr!!!`,TWN:`咯呃呃呃！！！`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L26_1`,type:`dialog`,speaker:`VILLAGER_BORDER_NULL_WOMAN`,text:{KOREA:`정신 차려……! 최대한 멀리 뛰는 거야……!`,JPN:`しっかり……！　できるだけ遠くまで走るのよ……！`,ENG:`Okay...! Now I just have to run far away...!`,TWN:`加油……！跑得越遠越好……！`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L27_1`,type:`dialog`,speaker:`VILLAGER_BORDER_NULL_WOMAN`,text:{KOREA:`아이들이 안전해질 때까지 마을에서 최대한 멀리……!`,JPN:`子供たちが安全になるまで、村からできるだけ遠く……！`,ENG:`Just far enough that the children will be safe...!`,TWN:`在確定孩子們安全無虞前，離村莊越遠越…！`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L33_1`,type:`dialog`,speaker:`VILLAGER_BORDER_NULL_WOMAN`,text:{KOREA:`헉……! 허억……! 다른 괴물들까지 전부……!`,JPN:`はっ……！　はあ……！　他の化け物まで全部……！`,ENG:`*Huff...!* *Huff...!* All the other monsters...!`,TWN:`呼…！呼呼……！其他怪物也都往我……！`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L34_1`,type:`dialog`,speaker:`VILLAGER_BORDER_NULL_WOMAN`,text:{KOREA:`이제 안 돼……! 더는 못 뛰겠어……!`,JPN:`もうダメ……！　もう走れない……！`,ENG:`I-I can't...! I can't run anymore...!`,TWN:`不行了……！我也跑不動了……！`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:null,R:null}}}];export{e as default};